from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal, InvalidOperation, ROUND_HALF_UP
from enum import Enum
from typing import Iterable


MoneyInput = Decimal | int | str


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when a product price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a product quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when a requested cart item does not exist."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


class DiscountType(Enum):
    """Supported discount types."""

    NONE = "none"
    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True)
class CartItem:
    """Represents one product line in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this cart item before discounts."""
        return self.unit_price * self.quantity


@dataclass(frozen=True)
class Discount:
    """Represents the active cart discount."""

    discount_type: DiscountType = DiscountType.NONE
    amount: Decimal = Decimal("0")


class ShoppingCart:
    """A shopping cart that manages items, discounts, and totals."""

    _CURRENCY_QUANTIZER = Decimal("0.01")

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount = Discount()

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart, increasing quantity if it already exists."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_unit_price = self._validate_unit_price(unit_price)
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)
        if existing_item is None:
            self._items[normalized_product_name] = CartItem(
                product_name=normalized_product_name,
                unit_price=validated_unit_price,
                quantity=validated_quantity,
            )
            return

        if existing_item.unit_price != validated_unit_price:
            raise InvalidPriceError(
                f"Product '{normalized_product_name}' is already in the cart "
                f"with unit price {existing_item.unit_price}."
            )

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=existing_item.quantity + validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = self._validate_product_name(product_name)
        self._get_item(normalized_product_name)
        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_item(normalized_product_name)

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=validated_quantity,
        )

    def subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return self._round_money(
            sum(item.line_total for item in self._items.values())
        )

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount to the cart total."""
        discount_percentage = self._to_decimal(percentage, "percentage discount")

        if discount_percentage < 0 or discount_percentage > 100:
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._discount = Discount(
            discount_type=DiscountType.PERCENTAGE,
            amount=discount_percentage,
        )

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat monetary discount to the cart total."""
        discount_amount = self._validate_discount_amount(amount)
        self._discount = Discount(
            discount_type=DiscountType.FLAT,
            amount=discount_amount,
        )

    def clear_discount(self) -> None:
        """Remove the active discount from the cart."""
        self._discount = Discount()

    def total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.subtotal()
        discount_amount = self._calculate_discount_amount(subtotal)
        return self._round_money(max(subtotal - discount_amount, Decimal("0")))

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their details."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self.clear_discount()

    def _get_item(self, product_name: str) -> CartItem:
        try:
            return self._items[product_name]
        except KeyError as error:
            raise ItemNotFoundError(
                f"Product '{product_name}' was not found in the cart."
            ) from error

    def _calculate_discount_amount(self, subtotal: Decimal) -> Decimal:
        if self._discount.discount_type is DiscountType.NONE:
            return Decimal("0")

        if self._discount.discount_type is DiscountType.PERCENTAGE:
            return self._round_money(subtotal * self._discount.amount / Decimal("100"))

        return min(self._discount.amount, subtotal)

    @classmethod
    def _validate_product_name(cls, product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_product_name = product_name.strip()
        if not normalized_product_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_product_name

    @classmethod
    def _validate_unit_price(cls, unit_price: MoneyInput) -> Decimal:
        validated_unit_price = cls._to_decimal(unit_price, "unit price")

        if validated_unit_price <= 0:
            raise InvalidPriceError("Unit price must be greater than zero.")

        return cls._round_money(validated_unit_price)

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

        return quantity

    @classmethod
    def _validate_discount_amount(cls, amount: MoneyInput) -> Decimal:
        discount_amount = cls._to_decimal(amount, "flat discount")

        if discount_amount < 0:
            raise InvalidDiscountError("Flat discount cannot be negative.")

        return cls._round_money(discount_amount)

    @staticmethod
    def _to_decimal(value: MoneyInput, field_name: str) -> Decimal:
        try:
            return Decimal(str(value))
        except (InvalidOperation, ValueError) as error:
            raise InvalidDiscountError(f"{field_name.capitalize()} must be numeric.") from error

    @classmethod
    def _round_money(cls, amount: Decimal) -> Decimal:
        return amount.quantize(cls._CURRENCY_QUANTIZER, rounding=ROUND_HALF_UP)
